        value = code,
        name = "lcom_execute"
    })
end)

local function lcom_execute_raw(code, label)
    local ok1, ret1 = pcall(function()
        return mpt.api.lcom.execute({value = code, name = label or "lcom_execute"})
    end)
    if ok1 then
        return ret1 ~= false, ret1
    end

    local ok2, ret2 = pcall(function()
        return mpt.api.lcom.execute(code, label or "lcom_execute")
    end)
    if ok2 then
        return ret2 ~= false, ret2
    end

    return false, tostring(ret1 or ret2)
end

